{
  "verses": [
    {
      "n": 16,
      "column": "left",
      "text": "Atjemi tam fawu Drebbi/\nfas zittu irr Galwa nehmis/ un\nfihlo winnu weena Swefcha\npehß."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Wiltus Maise irr da-\nscham falda/ bet pehzgallâ\ntaps winna Mutte pilla\nSwirgsdu."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Tahs Dohmas pastahw\nzaur Padohmu/ un zaur gud-\nreim Padohmeem jakarro."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Kas ta Mehlneffis stai-\nga/ tas isplukſchke fleppenu Lee-\ntu/ bet tu ne tinnees ar to/ kas\nar fawahm Luhpahn fmaida."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Kas fawu Tehwu un fa-\nwu Mahti lahd/ ta pascha Lukte\nisdiffigs wiffudsiftakâ Tum-\ntumâ."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Ta Manta/ us ko kas\npirmak wiffat steidsahs/ tahs pa-\nschas Gals ne buhs fivehtihts."
    },
    {
      "n": 22,
      "column": "left",
      "text": "Ne fakki: Es atreebschu\nto Launu/ gaidt us to KUN-\nGU/ tad wiꞥſch tew ispestihs."
    },
    {
      "n": 23,
      "column": "left",
      "text": "Diwejahds Swars irr\ntam KUNGAM weena Negan-\ntiba/ un wiltigs Swarru-Kaufs\nneiva labs."
    },
    {
      "n": 24,
      "column": "left",
      "text": "Ta Wihra Sohki nahk\nno ta KUNGA/ ka warretu\ntad tas Zilweks fawu Zelftu is-\nprast."
    },
    {
      "n": 25,
      "column": "left",
      "text": "Tas buhs Zilwekam par\nWalgu tahs fivehtas Leetas ee-\nriht/ un kad wiꞥſch apfohlijees\ntad wehl isinekleht."
    },
    {
      "n": 26,
      "column": "left",
      "text": "Weens gudrs Rehninsch\nistrenz tohs Besdeewigus/ un\nwed to Skritteli pahr teem."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Ta Zilweka Dwehfele irx\nta KUNGA Gatschuuns/ un\npahrbauda wiffu Sir̃dsdibbent."
    },
    {
      "n": 28,
      "column": "right",
      "text": "Schehlastiba un Patee-\nfiba pasarga to Rehnixu/ un\nzaur Labbadarri-chann stiprina\nwiꞥſch fawu Gohda-Krebslu."
    },
    {
      "n": 29,
      "column": "right",
      "text": "To Jauneſtu Krahsch-\nnuns irr winnu Spehks/ un\nfir̃mi Matti irr to Wezzajo\nGohds."
    },
    {
      "n": 30,
      "column": "right",
      "text": "* Bruhzas/ Wahtes/ un\nfir̃dsdibbenigas Mohzibas/ pee-\nnahk tam Launam par Schih-\nstifchanu.\n* Eebr: Wall: ir ta: Kad to Launo grib\nfehkiinstiht, jeb us Labbu west, tad tu:r wiꞥſch\nto par Bruhzahm. &c. &c &c."
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ta XXI. Nodalla.\nMahza/ ka Deews wiﬀas Leetas walduß starp\nteem Zilwekeem: 1. etc. Aprakſia dascha-\ndus Eikfumus un Netikfumus: 4.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "A Rehnixa Sir̃ds irr ta\nKUNGA Rohkâ/ ta\nUhdens Uppes/ un\nwiꞥſch lohka to kurp gribbe-\ndams."
    },
    {
      "n": 2,
      "column": "right",
      "text": "Wiffi Zelfti weena Wihra\nirr pareifs winna Azzis/ bet tas\nKUNGS pahrbanda tahs Sir-\ndis."
    },
    {
      "n": 3,
      "column": "right",
      "text": "Taisnibu un Teefu dar-\nriht/ pattik tam KUNGAM\nwaitak neka Uppuris."
    },
    {
      "n": 4,
      "column": "right",
      "text": "Lepnas Azzis un greſua\nSir̃ds/ (un) to Besdeewigu\nGatschuuns irr Brehki."
    },
    {
      "n": 5,
      "column": "right",
      "text": "Weena Tikfuscha Doh-\nmas nejs winnam Waitumm/\nbet wiﬀam/ kas fohti-steidsahs/\ntam peetruihks."
    }
  ],
  "confidence": "high",
